const astraItems = $('IF Empty').all();
const mailingItems = $input.all();

const existingKeys = new Set();
for (const item of mailingItems) {
  const k = (item.json.key || '').toString().trim();
  if (k) existingKeys.add(k);
}

const results = [];

for (const item of astraItems) {
  const row = item.json;
  const id = (row['ID'] || '').toString().trim();
  if (!id) continue;

  const company = (row['Наименование'] || '').toString().trim();

  // Segment detection from Рубрики
  const rubrics = (row['Рубрики'] || '').toString().toLowerCase();
  let segment = 'business';
  if (rubrics.includes('дизайн') || rubrics.includes('интерьер') || rubrics.includes('архитект')) {
    segment = 'designer';
  }

  const rawEmails = [row['E-mail 1'], row['E-mail 2']];
  const emails = [...new Set(
    rawEmails
      .filter(e => e != null && e.toString().trim() !== '')
      .map(e => e.toString().trim().toLowerCase())
  )];
  if (emails.length === 0) continue;

  let website = '';
  for (const f of ['Веб-сайт 1', 'Веб-сайт 2', 'Веб-сайт 3']) {
    const v = row[f];
    if (v != null && v.toString().trim() !== '') {
      website = v.toString().trim();
      if (!/^https?:\/\//i.test(website)) website = 'http://' + website;
      break;
    }
  }

  for (const email of emails) {
    const key = `${id}|${email}`;
    results.push({
      json: {
        key, email, company, segment, website,
        status: 'queued', sent_at: '', error: '',
        source_rowNumber: row['row_number'],
        source_ID: id,
        _action: existingKeys.has(key) ? 'update' : 'append'
      }
    });
  }
}

return results;

const row = { ...$json };
// == 1. SELECT BEST URL ==
const clean = (v) => (typeof v === 'string' ? v.trim() : '');
let url =
  clean(row["Веб-сайт 1"]) ||
  clean(row["Веб-сайт 2"]) ||
  clean(row["Веб-сайт 3"]) ||
  clean(row["2GIS URL"]) || '';
if (url) {
  url = url
    .replace(/^[\s"'<>()\[\]{}]+|[\s"'<>()\[\]{}]+$/g, '')
    .split(/[\s,;]+/)[0]
    .replace(/[),.;:\s]+$/g, '');
  if (url === '-' || url === '\u2013') url = '';
}
if (url) {
  if (url.startsWith('//')) url = `http:${url}`;
  else if (!/^https?:\/\//i.test(url)) url = `http://${url}`;
}
// == 2. FETCH (timeout 5s, limit 200KB) ==
let html = '';
if (url && /^https?:\/\//i.test(url)) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: {
        'User-Agent':
          'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
      },
      timeout: 5000,
      encoding: 'utf-8',
    });
    const raw = typeof resp === 'string' ? resp : JSON.stringify(resp ?? '');
    html = raw.length > 200000 ? raw.slice(0, 200000) : raw;
  } catch (e) {
    // timeout / error — пропускаем
  }
}
// == 3. QUICK EXIT если HTML пуст ==
if (!html) {
  return { json: { ...row, email_1: '', email_2: '' } };
}
// == 4. FILTERS ==
const FAKE_TLDS = /\.(png|jpg|jpeg|gif|svg|webp|css|js|woff2?|ttf|eot|ico|map|min)$/i;
const PLATFORM_DOMAINS = [
  'wixpress.com','wix.com','wixsite.com',
  'tilda.cc','tildacdn.com','tildacdn.info',
  'wordpress.com','wordpress.org','wp.com',
  'sentry.io','carrotquest.io','calltouch.ru','callibri.ru',
  '2gis.ru','2gis.com',
  'googleapis.com','googleusercontent.com','gstatic.com',
  'cloudflare.com','cloudflare-dns.com',
  'amazonaws.com',
  'mailchimp.com','mandrillapp.com',
  'sendgrid.net','sendgrid.com',
  'mailgun.org','mailgun.com',
  'bitrix24.com','bitrix.info','bitrix24.ru',
  'jivosite.com','jivo.ru',
  'yandex.net','yandex-team.ru',
  'google.com','facebook.com','meta.com',
  'w3.org','schema.org','ogp.me','gravatar.com',
  'example.com','example.org','test.com',
];
const JUNK_PREFIXES = /^(noreply|no-reply|no\.reply|mailer-daemon|postmaster|bounce|auto|daemon|root|abuse|null|devnull|undisclosed)/i;
const HEX_HASH = /^[0-9a-f-]{24,}$/i;
function isGoodEmail(email) {
  const idx = email.lastIndexOf('@');
  if (idx < 1) return false;
  const local = email.slice(0, idx);
  const domain = email.slice(idx + 1);
  if (!domain || !domain.includes('.')) return false;
  if (FAKE_TLDS.test(email)) return false;
  if (PLATFORM_DOMAINS.some(d => domain === d || domain.endsWith('.' + d))) return false;
  if (JUNK_PREFIXES.test(local)) return false;
  const cleanLocal = local.replace(/[.\-_]/g, '');
  if (HEX_HASH.test(cleanLocal) && cleanLocal.length > 24) return false;
  if (local.length > 50) return false;
  return true;
}
// == 5. EXTRACT (limit 50 matches max) ==
const EMAIL_RE = /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi;
const allMatches = html.match(EMAIL_RE) || [];
const deduped = [];
const seen = new Set();
for (const raw of allMatches.slice(0, 50)) {
  const e = raw.trim()
    .replace(/^[<("`[{]+|[>")'`\]}.,;:]+$/g, '')
    .toLowerCase();
  if (!e || seen.has(e) || !isGoodEmail(e)) continue;
  seen.add(e);
  deduped.push(e);
  if (deduped.length >= 2) break;
}
return {
  json: {
    ...row,
    email_1: deduped[0] || '',
    email_2: deduped[1] || '',
  },
};
